	const int inf = 1073741823;

	int e, bg[N], nx[M], to[M], wt[M];

	inline void link(int u, int v, int w) {

	    to[++e] = v;

	    nx[e] = bg[u];

	    wt[e] = w;

	    bg[u] = e;

	}

	int n, m, u, v, w;

