	    }

	    int nn = n << 1;

	    for (int i = 1; i <= n; ++i) {

	        for (int j = 1; j != nn; ++j)

	            h[j] = 0;

	        for (int j = 0; j <= n; ++j)

	            f[j] = inf;

	        f[i] = 0;

