	                if (f[j] + wt[k] < f[to[k]]) {

	                    f[to[k]] = f[j] + wt[k];

	                    update(to[k], to[k]);

	                }

	            }

	            update(j, 0);

	        }

	        for (int j = 1; j <= n; ++j)

