	#include <vector>

	const int MAXN = 100000;

	int n;

	int a[MAXN];

	long long ans;

	void solve(int l, int r) {

	    if (l + 1 == r) {

	        ans += a[l];

	        return;

	    }

	    int mid = (l + r) >> 1;

	    std::vector<int> pre(a + mid, a + r);

	    for (int i = 1; i < r - mid; ++i) ①;

	    std::vector<long long> sum(r - mid + 1);

	    for (int i = 0; i < r - mid; ++i)

